/* Better Dex service worker — generated by scripts/generate-sw.mjs, do not edit in dist/. */
const VERSION = "__VERSION__";
const SHELL = __SHELL__;
const SHELL_CACHE = `shell-${VERSION}`;
const IMG_CACHE = "images-v1";
const SPRITES_BASE = "https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon";

/*
 * The app is a fully static SPA: the shell (index.html + hashed JS/CSS/data
 * bundle) is a handful of files precached at install. Every route renders
 * client-side from the in-memory data bundle, so navigations never need the
 * network. Images are the only large assets: pixel sprites fill eagerly in
 * the background, the big artwork only via the download button.
 */

self.addEventListener("install", (event) => {
  event.waitUntil(
    (async () => {
      const cache = await caches.open(SHELL_CACHE);
      await Promise.all(
        SHELL.map(async (url) => {
          const response = await fetch(url);
          if (response.ok) await cache.put(url, response);
        }),
      );
      await self.skipWaiting();
    })(),
  );
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    (async () => {
      const keys = await caches.keys();
      await Promise.all(
        keys
          // "pages-*" are page caches of the old Next.js version of the app —
          // cleaned up on migration. The image cache (images-v1) is kept.
          .filter((key) => (key.startsWith("shell-") && key !== SHELL_CACHE) || key.startsWith("pages-"))
          .map((key) => caches.delete(key)),
      );
      await self.clients.claim();
    })(),
  );
});

/* ---------- background image fill (sprites eagerly, artwork on demand) ---------- */

let filling = false;

async function getImageManifest() {
  const cache = await caches.open(SHELL_CACHE);
  try {
    const response = await fetch(`/image-manifest.json?v=${VERSION}`);
    if (response.ok) {
      await cache.put("/image-manifest.json", response.clone());
      return response.json();
    }
  } catch {
    // Offline: fall through to the precached copy.
  }
  const cached = await cache.match("/image-manifest.json");
  if (!cached) throw new Error("image manifest unavailable");
  return cached.json();
}

async function broadcast(message) {
  const clients = await self.clients.matchAll({ includeUncontrolled: true });
  for (const client of clients) client.postMessage(message);
}

async function missingUrls(cache, urls) {
  const cached = new Set((await cache.keys()).map((request) => request.url));
  return urls.filter((url) => !cached.has(new URL(url, self.location.origin).href));
}

async function fillCache(includeArtwork) {
  if (filling) return;
  filling = true;
  try {
    const manifest = await getImageManifest();
    const shellCache = await caches.open(SHELL_CACHE);
    const imageCache = await caches.open(IMG_CACHE);

    const jobs = [
      // Heal partial installs: the shell is tiny, so re-checking is cheap.
      { cache: shellCache, urls: await missingUrls(shellCache, SHELL), external: false },
      { cache: imageCache, urls: await missingUrls(imageCache, manifest.sprites), external: true },
    ];
    if (includeArtwork) {
      jobs.push({ cache: imageCache, urls: await missingUrls(imageCache, manifest.artwork), external: true });
    }

    const total = jobs.reduce((sum, job) => sum + job.urls.length, 0);
    if (total === 0) {
      await broadcast({ type: "fill-done", failed: 0 });
      return;
    }

    let done = 0;
    let failed = 0;
    const CHUNK = 6;
    for (const job of jobs) {
      for (let i = 0; i < job.urls.length; i += CHUNK) {
        const chunk = job.urls.slice(i, i + CHUNK);
        await Promise.all(
          chunk.map(async (url) => {
            try {
              const request = job.external ? new Request(url, { mode: "cors" }) : url;
              const response = await fetch(request);
              if (response.ok) await job.cache.put(url, response);
              else failed += 1;
            } catch {
              failed += 1;
            }
            done += 1;
          }),
        );
        await broadcast({ type: "fill-progress", done, total, failed });
      }
    }
    await broadcast({ type: "fill-done", failed });
  } catch {
    await broadcast({ type: "fill-error" });
  } finally {
    filling = false;
  }
}

async function reportStatus(client) {
  try {
    const manifest = await getImageManifest();
    const shellCache = await caches.open(SHELL_CACHE);
    const imageCache = await caches.open(IMG_CACHE);
    const shellMissing = await missingUrls(shellCache, SHELL);
    const spritesMissing = await missingUrls(imageCache, manifest.sprites);
    const artworkMissing = await missingUrls(imageCache, manifest.artwork);
    client.postMessage({
      type: "status",
      version: VERSION,
      app: { total: SHELL.length, cached: SHELL.length - shellMissing.length },
      sprites: { total: manifest.sprites.length, cached: manifest.sprites.length - spritesMissing.length },
      artwork: { total: manifest.artwork.length, cached: manifest.artwork.length - artworkMissing.length },
    });
  } catch {
    client.postMessage({ type: "status-error" });
  }
}

async function resetCaches() {
  const keys = await caches.keys();
  await Promise.all(keys.map((key) => caches.delete(key)));
  // Re-seed the shell so the app keeps working after the reset.
  try {
    const cache = await caches.open(SHELL_CACHE);
    await Promise.all(
      SHELL.map(async (url) => {
        const response = await fetch(url);
        if (response.ok) await cache.put(url, response);
      }),
    );
  } catch {
    // Offline during reset: the shell returns on the next online visit.
  }
  await broadcast({ type: "reset-done" });
}

self.addEventListener("message", (event) => {
  const data = event.data || {};
  if (data.type === "fill") event.waitUntil(fillCache(false));
  if (data.type === "fill-artwork") event.waitUntil(fillCache(true));
  if (data.type === "reset") event.waitUntil(resetCaches());
  if (data.type === "status" && event.source) event.waitUntil(reportStatus(event.source));
});

/* ---------- fetch handling ---------- */

/** Serve the SPA shell for any navigation, refreshing it in the background. */
async function handleNavigate(event) {
  const cache = await caches.open(SHELL_CACHE);
  const cached = await cache.match("/");
  const refresh = fetch("/")
    .then(async (response) => {
      if (response.ok) await cache.put("/", response.clone());
      return response;
    })
    .catch(() => null);
  if (cached) {
    event.waitUntil(refresh);
    return cached;
  }
  return (await refresh) || Response.error();
}

async function cacheFirst(request, cacheName) {
  const cache = await caches.open(cacheName);
  const cached = await cache.match(request);
  if (cached) return cached;
  const response = await fetch(request);
  if (response.ok) cache.put(request, response.clone());
  return response;
}

async function handleImage(request, url) {
  const cache = await caches.open(IMG_CACHE);
  const cached = await cache.match(request.url);
  if (cached) return cached;
  try {
    const response = await fetch(new Request(request.url, { mode: "cors" }));
    if (response.ok) cache.put(request.url, response.clone());
    return response;
  } catch (error) {
    // Offline artwork fallback: shiny → normal artwork → pixel sprite of the same Pokémon.
    const match = url.pathname.match(/official-artwork\/(?:shiny\/)?(\d+)\.png$/);
    if (match) {
      const fallbacks = [
        `${SPRITES_BASE}/other/official-artwork/${match[1]}.png`,
        `${SPRITES_BASE}/${match[1]}.png`,
      ];
      for (const fallbackUrl of fallbacks) {
        if (fallbackUrl === request.url) continue;
        const fallback = await cache.match(fallbackUrl);
        if (fallback) return fallback;
      }
    }
    throw error;
  }
}

self.addEventListener("fetch", (event) => {
  const request = event.request;
  if (request.method !== "GET") return;
  const url = new URL(request.url);

  if (url.origin === self.location.origin) {
    if (request.mode === "navigate") {
      event.respondWith(handleNavigate(event));
      return;
    }
    if (url.pathname === "/image-manifest.json") {
      // Handled by getImageManifest inside the SW; pages never fetch it.
      return;
    }
    event.respondWith(cacheFirst(request, SHELL_CACHE));
    return;
  }

  if (url.hostname === "raw.githubusercontent.com") {
    event.respondWith(handleImage(request, url));
  }
});
